import React, { useState, useEffect, useMemo } from 'react';
import { fetchStudents } from './services/dataService';
import { findStudentsWithAI } from './services/aiService';
import { Student } from './types';
import { APP_TITLE, APP_SUBTITLE, VIBER_LINK, TELEGRAM_LINK } from './constants';
import StudentCard from './components/StudentCard';
import RegistrationForm from './components/RegistrationForm';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [view, setView] = useState<'search' | 'register'>('search');
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      const result = await fetchStudents();
      setStudents(result.students);
      setLoading(false);
    };
    loadData();
  }, []);

  const handleNewRegistration = (newStudent: Student) => {
    // Add to state immediately for responsiveness
    setStudents(prev => [newStudent, ...prev].sort((a, b) => a.name.localeCompare(b.name)));
    setView('search');
    setSearchTerm(newStudent.name);
  };

  useEffect(() => {
    if (!searchTerm.trim()) {
      setAiResults(null);
    }
  }, [searchTerm]);

  const handleSmartSearch = async () => {
    if (!searchTerm.trim()) return;
    setIsAiThinking(true);
    try {
      const ids = await findStudentsWithAI(searchTerm, students);
      setAiResults(ids);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAiThinking(false);
    }
  };

  const filteredStudents = useMemo(() => {
    const term = searchTerm.toLowerCase().trim().replace(/\s+/g, ' ');
    if (!term) return students;

    if (aiResults && aiResults.length > 0) {
      return students.filter(s => aiResults.includes(s.id));
    }

    return students
      .map(s => {
        const name = (s.name || '').toLowerCase();
        const city = (s.city || '').toLowerCase();
        const id = (s.id || '').toLowerCase();

        let score = 0;
        if (name.startsWith(term)) score = 100;
        else if (name.includes(term)) score = 80;
        else if (id.includes(term)) score = 60;
        else if (city.includes(term)) score = 40;

        return { student: s, score };
      })
      .filter(item => item.score > 0)
      .sort((a, b) => b.score - a.score)
      .map(item => item.student);
  }, [students, searchTerm, aiResults]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900">
      <header className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 text-white pt-12 pb-24 px-6 relative overflow-hidden shadow-2xl">
        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
          <div className="absolute top-[-10%] left-[-5%] w-96 h-96 bg-white rounded-full blur-[120px]"></div>
          <div className="absolute bottom-[-20%] right-[-5%] w-64 h-64 bg-indigo-400 rounded-full blur-[100px]"></div>
        </div>

        <div className="max-w-4xl mx-auto text-center relative z-10">
          <h1 className="text-4xl md:text-5xl font-extrabold mb-4 tracking-tight drop-shadow-md animate-in fade-in slide-in-from-top-4 duration-700">
            {APP_TITLE}
          </h1>
          <p className="text-blue-100 text-lg font-medium opacity-90 mb-8 px-4 animate-in fade-in slide-in-from-top-6 duration-700 delay-100">
            {APP_SUBTITLE}
            <br />
            <span className="text-xs font-normal opacity-80">(Level 2 Student ID ကောက်ခံခြင်း အစီအစဉ်)</span>
          </p>

          <div className="flex flex-col gap-3 max-w-sm mx-auto sm:max-w-none sm:flex-row sm:justify-center animate-in fade-in slide-in-from-top-8 duration-700 delay-200">
            <button 
              onClick={() => setView(view === 'search' ? 'register' : 'search')}
              className={`flex items-center justify-center gap-2 px-6 py-3.5 rounded-full text-sm font-bold shadow-lg border border-white/20 transition-all hover:scale-105 active:scale-95 ${view === 'register' ? 'bg-white text-blue-700' : 'bg-emerald-500 text-white hover:bg-emerald-600'}`}
            >
              {view === 'search' ? (
                <>
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><line x1="19" y1="8" x2="19" y2="14"/><line x1="22" y1="11" x2="16" y2="11"/></svg>
                  မှတ်ပုံတင်ရန် (Register)
                </>
              ) : (
                <>
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                  ပြန်ရှာရန် (Go Back to Search)
                </>
              )}
            </button>
            <div className="flex gap-2 justify-center">
               <a href={VIBER_LINK} target="_blank" rel="noopener noreferrer" className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-white/10 hover:bg-white/20 backdrop-blur-md px-5 py-3 rounded-full text-xs font-bold border border-white/10 transition-all">Viber</a>
               <a href={TELEGRAM_LINK} target="_blank" rel="noopener noreferrer" className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-white/10 hover:bg-white/20 backdrop-blur-md px-5 py-3 rounded-full text-xs font-bold border border-white/10 transition-all">Telegram</a>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl w-full mx-auto px-4 -mt-16 mb-32 flex-1 relative z-20">
        {view === 'search' ? (
          <>
            <div className="sticky top-4 z-30 mb-8">
              <div className="glass-morphism rounded-[2.5rem] p-5 shadow-2xl border border-white/60 ring-1 ring-slate-200/50 backdrop-blur-2xl">
                <div className="relative group">
                  <input 
                    type="text" 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
                    placeholder="နာမည် သို့မဟုတ် နေရပ်ဖြင့် ရှာဖွေပါ..." 
                    className="w-full pl-14 pr-32 py-4 rounded-[1.8rem] border-none ring-4 ring-slate-50 focus:ring-blue-500 bg-white shadow-inner outline-none transition-all text-lg font-medium text-slate-900 placeholder:text-slate-400"
                  />
                  <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                  </div>
                  <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-1">
                    {searchTerm && (
                      <button 
                        onClick={handleSmartSearch}
                        disabled={isAiThinking}
                        className={`flex items-center gap-2 px-4 py-2 rounded-2xl text-xs font-bold transition-all ${isAiThinking ? 'bg-slate-100 text-slate-400 cursor-wait' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-md active:scale-95'}`}
                      >
                        {isAiThinking ? (
                          <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                        ) : (
                          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/><path d="M5 3v4"/><path d="M19 17v4"/><path d="M3 5h4"/><path d="M17 19h4"/></svg>
                        )}
                        AI Help
                      </button>
                    )}
                  </div>
                </div>

                <div className="mt-4 flex items-center justify-between px-2">
                   <div className="flex items-center gap-2">
                     <div className="text-blue-600 bg-blue-50 px-4 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider border border-blue-100">
                       {searchTerm === '' 
                         ? `${students.length} Total Students` 
                         : `${filteredStudents.length} Results Found`}
