                     {aiResults && (
                       <span className="text-[10px] text-emerald-600 font-bold bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100 flex items-center gap-1">
                         <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                         AI Enhanced Results
                       </span>
                     )}
                   </div>
                   <div className="text-[9px] text-slate-400 font-bold uppercase tracking-widest flex items-center gap-1.5">
                     <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span>
                     {loading ? 'Connecting...' : 'Database Connected'}
                   </div>
                </div>
              </div>
            </div>

            <div className="space-y-5">
              {loading ? (
                <div className="flex flex-col items-center justify-center py-24">
                  <div className="w-12 h-12 border-4 border-slate-200 border-t-blue-600 rounded-full animate-spin mb-4"></div>
                  <p className="text-slate-500 font-bold text-sm">Syncing with Supabase...</p>
                </div>
              ) : filteredStudents.length === 0 ? (
                <div className="bg-white border-2 border-dashed border-slate-200 p-12 rounded-[2.5rem] text-center shadow-sm">
                  <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-300">
                    <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>
                  </div>
                  <h3 className="text-xl font-black text-slate-800 mb-2">ရှာမတွေ့ပါ (Not Found)</h3>
                  <p className="text-slate-500 text-sm font-medium mb-8">
                    ရိုက်ထည့်ထားသော အချက်အလက်ကို ပြန်စစ်ပေးပါ။<br/>
