export const fetchStudents = async (): Promise<FetchResult> => {
  try {
    const { data: supabaseStudents, error } = await supabase
      .from('students_id')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) {
      console.error('Supabase fetch error:', error);
      return { students: RAW_STUDENTS };
    }

    const transformed: Student[] = (supabaseStudents || []).map(row => ({
      id: row.id,
      name: row.name,
      city: row.city,
      originalData: row.original_data || {},
      createdAt: row.created_at
    }));

    const allStudentsMap = new Map<string, Student>();
    RAW_STUDENTS.forEach(s => allStudentsMap.set(s.id, s));
    transformed.forEach(s => allStudentsMap.set(s.id, s));

    return { students: Array.from(allStudentsMap.values()) };
  } catch (err) {
    console.error('Data fetch error:', err);
    return { students: RAW_STUDENTS };
  }
};

import React, { useMemo } from 'react';
import { Student } from '../types';

interface InsightsProps {
  students: Student[];
}

const Insights: React.FC<InsightsProps> = ({ students }) => {
  const stats = useMemo(() => {
    const locations: Record<string, number> = {};
    students.forEach(s => {
      const city = s.city?.trim().toUpperCase() || 'UNKNOWN';
      locations[city] = (locations[city] || 0) + 1;
    });

    const sortedLocations = Object.entries(locations)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 5);

    const latest = [...students]
      .filter(s => !!s.createdAt)
      .sort((a, b) => new Date(b.createdAt!).getTime() - new Date(a.createdAt!).getTime())
      .slice(0, 5);

    return {
      total: students.length,
      topLocations: sortedLocations,
      latestRegistrations: latest
    };
  }, [students]);

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-10 duration-700">
      {/* Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="glass-morphism rounded-[2.5rem] p-10 flex flex-col items-center justify-center border border-white shadow-2xl relative overflow-hidden group">
           <div className="absolute -top-10 -right-10 w-40 h-40 bg-blue-500/10 rounded-full blur-3xl group-hover:bg-blue-500/20 transition-all"></div>
           <h3 className="text-slate-400 text-xs font-black uppercase tracking-[0.2em] mb-4">Total Participants</h3>
           <div className="text-7xl font-black text-blue-600 tracking-tighter tabular-nums">
             {stats.total.toLocaleString()}
           </div>
           <p className="text-slate-500 text-sm mt-4 font-medium italic">"Learning Dhamma together"</p>
        </div>

        <div className="glass-morphism rounded-[2.5rem] p-10 border border-white shadow-2xl">
          <h3 className="text-slate-400 text-xs font-black uppercase tracking-[0.2em] mb-8 text-center md:text-left">Top Geographic Distribution</h3>
          <div className="space-y-4">
            {stats.topLocations.map(([city, count], idx) => {
              const percentage = Math.round((count / stats.total) * 100);
              return (
                <div key={city} className="space-y-1.5">
                  <div className="flex justify-between text-xs font-bold text-slate-600">
                    <span>{city}</span>
                    <span>{count} students ({percentage}%)</span>
                  </div>
                  <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-gradient-to-r from-blue-500 to-indigo-600 rounded-full transition-all duration-1000"
                      style={{ width: `${percentage}%`, transitionDelay: `${idx * 100}ms` }}
                    ></div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Live Activity Feed */}
      <div className="glass-morphism rounded-[2.5rem] p-10 border border-white shadow-2xl">
        <div className="flex items-center justify-between mb-8">
           <h3 className="text-slate-400 text-xs font-black uppercase tracking-[0.2em]">Latest Community Members</h3>
           <span className="flex items-center gap-1.5 text-[10px] font-bold text-emerald-500 uppercase bg-emerald-50 px-3 py-1 rounded-full">
             <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
             Live From Database
           </span>
        </div>

        <div className="space-y-4">
          {stats.latestRegistrations.length > 0 ? (
            stats.latestRegistrations.map((s, i) => (
              <div key={s.id} className="flex items-center justify-between p-4 rounded-2xl bg-white/50 border border-slate-100 hover:border-blue-200 transition-all group">
                <div className="flex items-center gap-4">
                  <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-100 to-indigo-100 flex items-center justify-center font-bold text-blue-600">
