                    {s.name.charAt(0)}
                  </div>
                  <div>
                    <div className="font-bold text-slate-800 text-sm group-hover:text-blue-600 transition-colors leading-tight">{s.name}</div>
                    <div className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">{s.city || 'YGN'}</div>
                  </div>
