          ) : (
            <div className="col-span-full text-center py-20 bg-slate-50/50 rounded-3xl border border-dashed border-slate-200">
              <div className="text-slate-300 mb-2">
                <svg className="mx-auto" xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="m15 9-6 6"/><path d="m9 9 6 6"/></svg>
