import React, { useState, useEffect, useMemo } from 'react';
import { fetchStudents } from './services/dataService';
import { findStudentsWithAI } from './services/aiService';
import { Student } from './types';
import { APP_TITLE, APP_SUBTITLE, translations } from './constants';
import StudentCard from './components/StudentCard';
import Insights from './components/Insights';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [view, setView] = useState<'search' | 'insights'>('search');
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [aiResults, setAiResults] = useState<string[] | null>(null);
  const [lang, setLang] = useState<'my' | 'en'>('my');

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      const result = await fetchStudents();
      setStudents(result.students);
      setLoading(false);
    };
    loadData();
  }, []);

  const t = (key: keyof typeof translations['en']): string => {
    return (translations[lang] as any)[key] || (translations['en'] as any)[key];
  };

  const handleSmartSearch = async () => {
    if (!searchTerm.trim()) return;
    setIsAiThinking(true);
    try {
      const ids = await findStudentsWithAI(searchTerm, students);
      setAiResults(ids);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAiThinking(false);
    }
  };

  const filteredStudents = useMemo(() => {
    const term = searchTerm.toLowerCase().trim();
    if (!term) return students.sort((a, b) => a.name.localeCompare(b.name));

    if (aiResults && aiResults.length > 0) {
      return students.filter(s => aiResults.includes(s.id));
    }

    return students
      .filter(s => 
        s.name.toLowerCase().includes(term) || 
        s.id.toLowerCase().includes(term) || 
        s.city.toLowerCase().includes(term)
      )
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [students, searchTerm, aiResults]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900">
      <header className="bg-gradient-to-br from-blue-700 via-indigo-700 to-indigo-900 text-white pt-10 pb-24 px-6 relative overflow-hidden shadow-2xl">
        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
          <div className="absolute top-[-10%] left-[-5%] w-96 h-96 bg-white rounded-full blur-[120px]"></div>
          <div className="absolute bottom-[-20%] right-[-5%] w-64 h-64 bg-blue-400 rounded-full blur-[100px]"></div>
        </div>

        {/* Improved Language Switcher Toggle */}
        <div className="max-w-4xl mx-auto flex justify-end mb-6 relative z-30">
          <div className="bg-white/10 backdrop-blur-md rounded-full p-1 border border-white/20 shadow-lg flex items-center">
             <button 
               onClick={() => setLang('my')}
               className={`px-4 py-1.5 rounded-full text-[11px] font-black tracking-widest transition-all duration-300 ${lang === 'my' ? 'bg-white text-blue-700 shadow-md scale-105' : 'text-white/70 hover:text-white'}`}
             >
               မြန်မာ
             </button>
             <button 
               onClick={() => setLang('en')}
               className={`px-4 py-1.5 rounded-full text-[11px] font-black tracking-widest transition-all duration-300 ${lang === 'en' ? 'bg-white text-blue-700 shadow-md scale-105' : 'text-white/70 hover:text-white'}`}
             >
               ENGLISH
             </button>
          </div>
        </div>

        <div className="max-w-4xl mx-auto text-center relative z-10">
          <h1 className="text-4xl md:text-5xl font-extrabold mb-4 tracking-tight drop-shadow-md animate-in fade-in slide-in-from-top-4 duration-700">
            {APP_TITLE}
          </h1>
          <p className="text-blue-100 text-lg font-medium opacity-90 mb-10 animate-in fade-in slide-in-from-top-6 duration-700 delay-100">
            {APP_SUBTITLE}
          </p>

          <div className="flex items-center justify-center p-1 bg-white/10 backdrop-blur-xl rounded-[2rem] border border-white/10 max-w-xs mx-auto shadow-inner animate-in fade-in zoom-in duration-700 delay-200">
             <button 
               onClick={() => setView('search')}
               className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.8rem] text-xs font-bold transition-all ${view === 'search' ? 'bg-white text-blue-700 shadow-xl' : 'text-white/70 hover:text-white'}`}
             >
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
               {t('findId')}
             </button>

             <button 
               onClick={() => setView('insights')}
               className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.8rem] text-xs font-bold transition-all ${view === 'insights' ? 'bg-white text-blue-700 shadow-xl' : 'text-white/70 hover:text-white'}`}
             >
               <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 20v-6"/><path d="M6 20V10"/><path d="M18 20V4"/></svg>
               {t('insights')}
             </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl w-full mx-auto px-4 -mt-12 mb-32 flex-1 relative z-20">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-32 glass-morphism rounded-[3rem] shadow-xl">
            <div className="w-16 h-16 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin mb-6"></div>
            <p className="text-slate-500 font-black text-xs uppercase tracking-widest animate-pulse">{t('syncing')}</p>
          </div>
        ) : view === 'search' ? (
          <>
            <div className="sticky top-4 z-30 mb-8">
              <div className="glass-morphism rounded-[2.5rem] p-5 shadow-2xl border border-white ring-1 ring-slate-200/50">
                <div className="relative group">
                  <input 
                    type="text" 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSmartSearch()}
                    placeholder={t('searchPlaceholder')}
                    className="w-full pl-14 pr-32 py-4 rounded-[1.8rem] border-none ring-4 ring-slate-50 focus:ring-blue-500 bg-white shadow-inner outline-none transition-all text-lg font-medium text-slate-900 placeholder:text-slate-300"
                  />
                  <div className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300">
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
                  </div>
                  <div className="absolute right-3 top-1/2 -translate-y-1/2">
                    {searchTerm && (
                      <button 
                        onClick={handleSmartSearch}
                        disabled={isAiThinking}
                        className={`flex items-center gap-2 px-4 py-2 rounded-2xl text-xs font-black transition-all ${isAiThinking ? 'bg-slate-100 text-slate-400' : 'bg-blue-600 text-white hover:bg-blue-700 shadow-lg active:scale-95'}`}
                      >
                        {isAiThinking ? <div className="w-3 h-3 border-2 border-slate-300 border-t-slate-500 rounded-full animate-spin"></div> : t('idSearch')}
                      </button>
                    )}
                  </div>
                </div>
                <div className="mt-4 flex items-center justify-between px-2 text-[10px] font-black uppercase tracking-widest text-slate-400">
                   <div>{filteredStudents.length} {t('recordsFound')}</div>
                   <div className="flex items-center gap-1.5 text-blue-500 bg-blue-50 px-3 py-1 rounded-full border border-blue-100">
                     <span className="w-1.5 h-1.5 bg-blue-500 rounded-full"></span>
                     {t('supabaseLinked')}
                   </div>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 gap-6 pb-20">
              {filteredStudents.length === 0 ? (
                <div className="bg-white border-2 border-dashed border-slate-200 p-20 rounded-[3rem] text-center">
                  <h3 className="text-xl font-black text-slate-800 mb-2">{t('noResults')}</h3>
                  <p className="text-slate-400 text-sm mb-4">{t('adjustSearch')}</p>
                </div>
              ) : (
                filteredStudents.map((student, index) => (
                  <StudentCard key={student.id} student={student} index={index} searchTerm={searchTerm} lang={lang} />
                ))
              )}
            </div>
          </>
        ) : (
          <Insights students={students} lang={lang} />
        )}
      </main>

      <footer className="py-12 text-center opacity-30">
        <p className="text-slate-400 text-[9px] uppercase tracking-[0.3em] font-black">{t('communityFooter')}</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Student } from '../types';
import { VIBER_LINK, TELEGRAM_LINK, PATRON_WEBSITE_LINK, translations } from '../constants';

interface InsightsProps {
  students: Student[];
  lang: 'my' | 'en';
}

const Insights: React.FC<InsightsProps> = ({ students, lang }) => {
  const [selectedCity, setSelectedCity] = useState<string | null>(null);
  const [citySearchQuery, setCitySearchQuery] = useState('');

  const t = (key: keyof typeof translations['en']): string => {
    return (translations[lang] as any)[key] || (translations['en'] as any)[key];
  };

  const stats = useMemo(() => {
    const locations: Record<string, number> = {};
    students.forEach(s => {
      const city = s.city?.trim().toUpperCase() || 'UNKNOWN';
      locations[city] = (locations[city] || 0) + 1;
    });

    const allLocations = Object.entries(locations).sort(([, a], [, b]) => b - a);

    const filteredStudents = selectedCity 
      ? students.filter(s => (s.city?.trim().toUpperCase() || 'UNKNOWN') === selectedCity)
      : [...students].filter(s => !!s.createdAt).sort((a, b) => new Date(b.createdAt!).getTime() - new Date(a.createdAt!).getTime()).slice(0, 10);

    return {
      total: students.length,
      allLocations,
      filteredStudents,
      totalCities: allLocations.length
    };
  }, [students, selectedCity]);

  const displayCities = useMemo(() => {
    if (!citySearchQuery) return stats.allLocations;
    return stats.allLocations.filter(([city]) => 
      city.toLowerCase().includes(citySearchQuery.toLowerCase())
    );
  }, [stats.allLocations, citySearchQuery]);

  // Helper to format the list header based on language
  const renderListHeader = () => {
    if (!selectedCity) return t('latestMembers');

    if (lang === 'my') {
      return `${selectedCity} ${t('membersIn')} (${stats.filteredStudents.length})`;
    }
    return `${t('membersIn')} ${selectedCity} (${stats.filteredStudents.length})`;
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-10 duration-700">
      {/* Overview and City Filter */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="glass-morphism rounded-[2.5rem] p-10 flex flex-col items-center justify-center border border-white shadow-2xl relative overflow-hidden group">
           <div className="absolute -top-10 -right-10 w-40 h-40 bg-blue-500/10 rounded-full blur-3xl group-hover:bg-blue-500/20 transition-all"></div>
           <h3 className="text-slate-400 text-xs font-black uppercase tracking-[0.2em] mb-4">{t('totalParticipants')}</h3>
           <div className="text-7xl font-black text-blue-600 tracking-tighter tabular-nums">{stats.total.toLocaleString()}</div>
           <p className="text-slate-500 text-sm mt-4 font-medium italic">"Learning Dhamma together"</p>
        </div>

        <div className="glass-morphism rounded-[2.5rem] p-8 border border-white shadow-2xl flex flex-col">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-slate-400 text-xs font-black uppercase tracking-[0.2em]">{t('distByCity')} ({stats.totalCities})</h3>
            <div className="relative">
              <input 
                type="text" 
                placeholder={t('filterCity')}
                value={citySearchQuery}
                onChange={(e) => setCitySearchQuery(e.target.value)}
                className="bg-slate-200/60 border border-slate-300/50 text-slate-800 rounded-full px-4 py-1.5 text-[11px] font-bold focus:ring-2 focus:ring-blue-500 focus:bg-white outline-none w-40 shadow-inner placeholder:text-slate-400 transition-all"
              />
            </div>
          </div>

          <div className="space-y-3 overflow-y-auto max-h-[180px] pr-2 custom-scrollbar">
            {displayCities.map(([city, count], idx) => {
              const percentage = Math.round((count / stats.total) * 100);
              const isActive = selectedCity === city;
              return (
                <button 
                  key={city} 
                  onClick={() => setSelectedCity(isActive ? null : city)}
                  className={`w-full text-left group transition-all p-2 rounded-xl border ${isActive ? 'bg-blue-600 border-blue-500 shadow-lg scale-[1.02]' : 'bg-white/50 border-transparent hover:border-slate-200'}`}
                >
                  <div className="flex justify-between text-[10px] font-bold mb-1">
                    <span className={isActive ? 'text-white' : 'text-slate-600'}>{city}</span>
                    <span className={isActive ? 'text-blue-100' : 'text-slate-400'}>{count} ({percentage}%)</span>
                  </div>
                  <div className={`h-1.5 w-full rounded-full overflow-hidden ${isActive ? 'bg-blue-800/50' : 'bg-slate-100'}`}>
                    <div 
                      className={`h-full rounded-full transition-all duration-1000 ${isActive ? 'bg-white' : 'bg-gradient-to-r from-blue-400 to-indigo-500'}`}
                      style={{ width: `${percentage || 1}%` }}
                    ></div>
                  </div>
                </button>
              );
            })}
          </div>
          {selectedCity && (
            <button onClick={() => setSelectedCity(null)} className="mt-4 text-[10px] font-black text-blue-500 uppercase tracking-widest hover:underline text-center w-full bg-blue-50 py-2 rounded-lg border border-blue-100">{t('clearFilter')}</button>
          )}
        </div>
      </div>

      {/* Filtered Member Directory */}
      <div className="glass-morphism rounded-[2.5rem] p-10 border border-white shadow-2xl">
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
           <div>
             <h3 className="text-slate-500 text-sm font-black uppercase tracking-[0.2em]">
               {renderListHeader()}
             </h3>
             {selectedCity && <p className="text-[10px] font-medium text-slate-400 mt-1 uppercase tracking-widest">Verified Data Entry</p>}
           </div>
           {!selectedCity && (
             <span className="flex items-center gap-1.5 text-[10px] font-bold text-emerald-500 uppercase bg-emerald-50 px-3 py-1 rounded-full w-fit border border-emerald-100">
               <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
               {t('liveFeed')}
             </span>
           )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {stats.filteredStudents.length > 0 ? (
            stats.filteredStudents.map((s, i) => (
              <div key={s.id} className="flex items-center justify-between p-4 rounded-2xl bg-white/50 border border-slate-100 hover:border-blue-200 transition-all group animate-in zoom-in duration-300">
                <div className="flex items-center gap-3">
                  <div className="w-9 h-9 rounded-full bg-gradient-to-br from-blue-100 to-indigo-100 flex items-center justify-center font-bold text-blue-600 text-xs shadow-sm border border-white">{s.name.charAt(0)}</div>
                  <div>
                    <div className="font-bold text-slate-800 text-sm group-hover:text-blue-700 transition-colors leading-tight">{s.name}</div>
                    <div className="text-[9px] text-slate-400 font-bold uppercase tracking-wider mt-0.5">{s.city || 'YGN'}</div>
                  </div>
                </div>
                <div className="text-[11px] font-mono font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-xl border border-blue-100 shadow-sm group-hover:bg-blue-600 group-hover:text-white transition-all">
                  {s.id}
                </div>
              </div>
            ))
          ) : (
            <div className="col-span-full text-center py-20 bg-slate-50/50 rounded-3xl border border-dashed border-slate-200">
              <div className="text-slate-400 text-sm font-bold uppercase tracking-widest">{t('noMembers')}</div>
            </div>
          )}
        </div>
      </div>

      {/* Patron Section */}
      <div className="glass-morphism rounded-[2.5rem] p-8 border-2 border-amber-100 shadow-2xl relative overflow-hidden group bg-gradient-to-br from-white to-amber-50/30">
        <div className="relative z-10 flex flex-col items-center text-center">
          <div className="inline-block px-4 py-1.5 rounded-full bg-amber-100 text-amber-800 text-[10px] font-black uppercase tracking-[0.2em] mb-6">{t('leaderPatron')}</div>
          <h2 className="text-xl md:text-2xl font-black text-slate-800 mb-4 leading-relaxed whitespace-pre-line">{t('patronName')}</h2>
          <a href={PATRON_WEBSITE_LINK} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-3 bg-amber-600 hover:bg-amber-700 text-white px-8 py-4 rounded-[1.5rem] font-bold shadow-xl shadow-amber-200 transition-all active:scale-95 group">
            {t('visitWebsite')}
            <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="group-hover:translate-x-1 transition-transform"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg>
          </a>
        </div>
      </div>

      {/* Community Links */}
      <div className="glass-morphism rounded-[2.5rem] p-10 border border-white shadow-2xl">
        <h3 className="text-slate-400 text-xs font-black uppercase tracking-[0.2em] mb-8">{t('stayUpdated')}</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <a href={VIBER_LINK} target="_blank" rel="noopener noreferrer" className="flex items-center gap-5 p-6 rounded-3xl bg-[#7360f2]/5 border border-[#7360f2]/10 hover:bg-[#7360f2]/10 hover:border-[#7360f2]/30 transition-all group shadow-sm">
            <div className="w-14 h-14 rounded-2xl bg-[#7360f2] flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform"><svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/></svg></div>
            <div>
              <div className="font-black text-slate-800 text-lg">{t('viberGroup')}</div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-wider">{t('joinAnnouncements')}</div>
            </div>
          </a>
          <a href={TELEGRAM_LINK} target="_blank" rel="noopener noreferrer" className="flex items-center gap-5 p-6 rounded-3xl bg-[#24A1DE]/5 border border-[#24A1DE]/10 hover:bg-[#24A1DE]/10 hover:border-[#24A1DE]/30 transition-all group shadow-sm">
            <div className="w-14 h-14 rounded-2xl bg-[#24A1DE] flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform"><svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m22 2-7 20-4-9-9-4Z"/><path d="M22 2 11 13"/></svg></div>
            <div>
              <div className="font-black text-slate-800 text-lg">{t('telegramChannel')}</div>
              <div className="text-xs text-slate-500 font-bold uppercase tracking-wider">{t('instantUpdates')}</div>
            </div>
          </a>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: rgba(0,0,0,0.03); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(59, 130, 246, 0.4); border-radius: 10px; border: 1px solid white; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(59, 130, 246, 0.6); }
      `}</style>
    </div>
  );
};

export default Insights;
